import { toTags } from '../tag.js';
import { getItem } from './item.js';
import { toLevelItem } from './level.js';
import { toUserItem } from './user.js';
export const toPlaylistItem = (sonolus, localize, item) => ({
    name: item.name,
    source: sonolus.address,
    version: item.version,
    title: localize(item.title),
    subtitle: localize(item.subtitle),
    author: localize(item.author),
    authorUser: item.authorUser
        ? toUserItem(sonolus, localize, getItem(sonolus.user.items, item.authorUser, `Playlist/${item.name}`, '.authorUser'))
        : undefined,
    tags: toTags(localize, item.tags),
    levels: item.levels.map((level, index) => toLevelItem(sonolus, localize, getItem(sonolus.level.items, level, `Playlist/${item.name}`, `.levels[${index}]`))),
    thumbnail: item.thumbnail,
});
